#!/usr/bin/env node
/**
 * presence_init.js — Initialize .presence.json for all 34 agents
 */
const fs = require('fs');
const path = require('path');

const AGENTS = [
  'master-orchestrator',
  'prompt-optimizer',
  'agile-product-owner',
  'market-intelligence',
  'product-strategy',
  'content-strategy',
  'ai-seo',
  'seo-audit',
  'product-marketing-context',
  'senior-architect',
  'database-schema-designer',
  'database-reviewer',
  'ui-design-system',
  'ui-ux-pro-max',
  'epic-design',
  'stitch-design',
  'stitch-loop',
  'senior-backend',
  'senior-frontend',
  'shadcn-expert',
  'clean-code',
  'coding-standards',
  'typescript-reviewer',
  'refactor-cleaner',
  'realistic-seeder',
  'planner',
  'senior-qa',
  'code-reviewer',
  'playwright-pro',
  'performance-optimizer',
  'senior-security',
  'security-reviewer',
  'senior-devops',
  'harness-optimizer'
];

const PRESENCE_DIR = __dirname;

AGENTS.forEach(agentId => {
  const filePath = path.join(PRESENCE_DIR, `${agentId}.json`);
  if (!fs.existsSync(filePath)) {
    const entry = {
      agent_id: agentId,
      status: 'unknown',
      task: null,
      project: null,
      updated_at: new Date().toISOString()
    };
    fs.writeFileSync(filePath, JSON.stringify(entry, null, 2));
    console.log(`✅ Initialized: ${agentId}`);
  } else {
    console.log(`⏩ Already exists: ${agentId}`);
  }
});

console.log(`\n🎉 Presence system initialized for ${AGENTS.length} agents.`);

#!/usr/bin/env node
/**
 * presence_set.js — Update an agent's own presence status
 * Usage: node presence_set.js --agent senior-backend --status active --task "building auth" --project ahv-qlhv-be
 */
const fs = require('fs');
const path = require('path');

const args = process.argv.slice(2);
const get = (flag) => {
  const idx = args.indexOf(`--${flag}`);
  return idx !== -1 ? args[idx + 1] : null;
};

const agentId = get('agent');
const status = get('status');
const task = get('task');
const project = get('project');

if (!agentId || !status) {
  console.error('Usage: node presence_set.js --agent <id> --status <active|idle|failed|unknown> [--task "..."] [--project "..."]');
  process.exit(1);
}

const VALID_STATUSES = ['active', 'idle', 'failed', 'unknown'];
if (!VALID_STATUSES.includes(status)) {
  console.error(`Invalid status. Must be one of: ${VALID_STATUSES.join(', ')}`);
  process.exit(1);
}

const filePath = path.join(__dirname, `${agentId}.json`);
const entry = {
  agent_id: agentId,
  status,
  task: task || null,
  project: project || null,
  updated_at: new Date().toISOString()
};

fs.writeFileSync(filePath, JSON.stringify(entry, null, 2));
console.log(`✅ ${agentId} → ${status}${task ? ` | ${task}` : ''}${project ? ` (@ ${project})` : ''}`);

#!/usr/bin/env node
/**
 * presence_broadcast.js — Read all agent presence files and format for Telegram
 * Used by master-orchestrator to broadcast status table
 */
const fs = require('fs');
const path = require('path');

const PRESENCE_DIR = __dirname;

const files = fs.readdirSync(PRESENCE_DIR).filter(f => f.endsWith('.json') && f !== 'schema.json');

const agents = files.map(file => {
  try {
    return JSON.parse(fs.readFileSync(path.join(PRESENCE_DIR, file), 'utf8'));
  } catch {
    return null;
  }
}).filter(Boolean);

const STATUS_SYMBOLS = {
  active: '🟢',
  idle: '⚪',
  failed: '🔴',
  unknown: '⚪'
};

const lines = [];
lines.push('🌐 *Orbis — Agent Presence Board*');
lines.push('');

const active = agents.filter(a => a.status === 'active');
const idle = agents.filter(a => a.status === 'idle');
const failed = agents.filter(a => a.status === 'failed');
const unknown = agents.filter(a => a.status === 'unknown');

lines.push(`🟢 Active: ${active.length}  ⚪ Idle: ${idle.length}  🔴 Failed: ${failed.length}  ⚪ Unknown: ${unknown.length}`);
lines.push('');

if (active.length) {
  lines.push('*Active:*');
  active.forEach(a => {
    lines.push(`  ${STATUS_SYMBOLS[a.status]} \`${a.agent_id}\` — ${a.task || 'no task'}${a.project ? ` (@ ${a.project})` : ''}`);
  });
  lines.push('');
}

if (failed.length) {
  lines.push('*Failed:*');
  failed.forEach(a => {
    lines.push(`  🔴 \`${a.agent_id}\` — ${a.task || 'no task'}`);
  });
  lines.push('');
}

if (!active.length && !failed.length) {
  lines.push('_No active or failed agents._');
}

console.log(lines.join('\n'));

