'use client';

import React, { useState, useEffect } from 'react';
import { CalendarCheck, CalendarX, Zap, Eye, X, CheckCircle2, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { getTodayMilestones, bulkUpdateCourseStatus } from '@/src/services/courseService';
import { useAuth } from '@/src/context/AuthContext';

interface CourseMilestone {
  _id: string;
  name: string;
  start_date?: string;
  end_date?: string;
  student_count: number;
}

// Demo data for testing when no real data available
const DEMO_MILESTONES: Milestones = {
  openingCourses: [
    { _id: 'demo1', name: 'Khóa B2 - Sáng thứ 2', start_date: new Date().toISOString(), student_count: 28 },
    { _id: 'demo2', name: 'Khóa B1 - Tối thứ 2', start_date: new Date().toISOString(), student_count: 35 },
    { _id: 'demo3', name: 'Khóa C1 - Đã quá hạn KG', start_date: new Date(Date.now() - 3 * 86400000).toISOString(), student_count: 18 },
  ],
  closingCourses: [
    { _id: 'demo4', name: 'Khóa A1 - Sáng thứ 7', end_date: new Date().toISOString(), student_count: 22 },
    { _id: 'demo5', name: 'Khóa A2 - Đã quá hạn KT', end_date: new Date(Date.now() - 5 * 86400000).toISOString(), student_count: 30 },
  ],
  openingCount: 3,
  closingCount: 2,
  overdueOpeningCount: 1,
  overdueClosingCount: 1,
};

interface Milestones {
  openingCourses: CourseMilestone[];
  closingCourses: CourseMilestone[];
  openingCount: number;
  closingCount: number;
  overdueOpeningCount?: number;
  overdueClosingCount?: number;
}

interface CourseMilestoneBannerProps {
  teacherId?: string;
  /** Force show demo banner (for preview/testing) */
  demoMode?: boolean;
}

const CourseMilestoneBanner: React.FC<CourseMilestoneBannerProps> = ({ demoMode = false }) => {
  const { user } = useAuth();
  const [milestones, setMilestones] = useState<Milestones | null>(null);
  const [loading, setLoading] = useState(true);
  const [processing, setProcessing] = useState(false);
  const [showReviewModal, setShowReviewModal] = useState(false);
  const [reviewTab, setReviewTab] = useState<'opening' | 'closing'>('opening');
  const [selectedCourses, setSelectedCourses] = useState<Set<string>>(new Set());
  const [dismissed, setDismissed] = useState(false);

  useEffect(() => {
    // Demo mode: show demo data immediately
    if (demoMode) {
      setMilestones(DEMO_MILESTONES);
      setLoading(false);
      return;
    }

    if (!user || user.role !== 'teacher') { setLoading(false); return; }

    getTodayMilestones()
      .then((res: any) => {
        if (res?.success && (res.data?.openingCount > 0 || res.data?.closingCount > 0)) {
          setMilestones(res.data);
        }
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [demoMode, user]);

  if (loading || dismissed) return null;
  if (!milestones || (milestones.openingCount === 0 && milestones.closingCount === 0)) return null;

  const handleAutoUpdate = async () => {
    setProcessing(true);
    try {
      const promises: Promise<any>[] = [];

      if (milestones.openingCount > 0) {
        const ids = milestones.openingCourses.map((c) => c._id);
        promises.push(
          bulkUpdateCourseStatus(ids, 'ongoing').then((res) => {
            if (!res?.success) throw new Error(res?.message || 'Lỗi cập nhật khai giảng');
          })
        );
      }

      if (milestones.closingCount > 0) {
        const ids = milestones.closingCourses.map((c) => c._id);
        promises.push(
          bulkUpdateCourseStatus(ids, 'completed').then((res) => {
            if (!res?.success) throw new Error(res?.message || 'Lỗi cập nhật kết thúc');
          })
        );
      }

      await Promise.all(promises);
      toast.success('Đã cập nhật trạng thái khóa học tự động!');
      setDismissed(true);
      window.dispatchEvent(new CustomEvent('refresh-dashboard'));
    } catch (err: any) {
      toast.error(err?.message || 'Có lỗi xảy ra khi cập nhật.');
    } finally {
      setProcessing(false);
    }
  };

  const handleManualUpdate = () => {
    setSelectedCourses(new Set());
    setShowReviewModal(true);
    setReviewTab(milestones.openingCount > 0 ? 'opening' : 'closing');
  };

  const handleSubmitManual = async () => {
    if (selectedCourses.size === 0) {
      toast.error('Vui lòng chọn ít nhất một khóa học để cập nhật.');
      return;
    }

    const newStatus = reviewTab === 'opening' ? 'ongoing' : 'completed';
    setProcessing(true);
    try {
      const res: any = await bulkUpdateCourseStatus(Array.from(selectedCourses), newStatus);
      if (res?.success) {
        toast.success('Đã cập nhật trạng thái khóa học!');
        setShowReviewModal(false);
        setDismissed(true);
        window.dispatchEvent(new CustomEvent('refresh-dashboard'));
      } else {
        toast.error(res?.message || 'Có lỗi xảy ra.');
      }
    } catch (err: any) {
      toast.error(err?.message || 'Có lỗi xảy ra khi cập nhật.');
    } finally {
      setProcessing(false);
    }
  };

  const toggleCourse = (id: string) => {
    setSelectedCourses((prev) => {
