                  <CalendarCheck className="w-4 h-4" />
                  <span>{milestones.openingCount} khóa khai giảng</span>
                  {(milestones.overdueOpeningCount ?? 0) > 0 && (
                    <span className="bg-amber-400 text-amber-900 px-1.5 py-0.5 rounded-full text-[10px] font-black">
                      {milestones.overdueOpeningCount} quá hạn
                    </span>
                  )}
                </div>
              )}
              {milestones.closingCount > 0 && (
                <div className="flex items-center gap-1.5 bg-rose-600 text-white px-3 py-1.5 rounded-xl text-xs font-black">
                  <CalendarX className="w-4 h-4" />
                  <span>{milestones.closingCount} khóa kết thúc</span>
