            <p className="text-xs text-gray-500 font-medium">
              Một số khóa học có cột mốc cần cập nhật — bao gồm khóa quá hạn chưa được xử lý.
            </p>
            <div className="flex items-center gap-2 pt-1">
              <button
                onClick={handleAutoUpdate}
                disabled={processing}
                className="flex items-center gap-1.5 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-xs font-bold transition-all active:scale-95 disabled:opacity-60 shadow-sm"
              >
                {processing ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Zap className="w-3.5 h-3.5" />}
