async getTodayMilestones(teacherId: string) {
    const teacherOid = new mongoose.Types.ObjectId(teacherId);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);

    // Courses starting today (Sắp KG -> Đang học)
    const openingCourses = await CourseStudentModel.aggregate([
      { $match: { teacher_id: teacherOid } },
      {
        $lookup: {
          from: 'courseinfos',
          localField: 'course_id',
          foreignField: '_id',
          as: 'course',
        },
      },
      { $unwind: { path: '$course', preserveNullAndEmptyArrays: false } },
      {
        $match: {
          'course.start_date': { $gte: today, $lt: tomorrow },
          'course.status': 'draft',
        },
      },
      {
        $project: {
          _id: '$course._id',
          name: '$course.name',
          start_date: '$course.start_date',
          end_date: '$course.end_date',
          status: '$course.status',
          student_count: 1,
        },
      },
    ]);

    // Courses ending today (Đang học -> Đã kết thúc)
    const closingCourses = await CourseStudentModel.aggregate([
      { $match: { teacher_id: teacherOid } },
      {
        $lookup: {
          from: 'courseinfos',
          localField: 'course_id',
          foreignField: '_id',
          as: 'course',
        },
      },
      { $unwind: { path: '$course', preserveNullAndEmptyArrays: false } },
      {
        $match: {
          'course.end_date': { $gte: today, $lt: tomorrow },
          'course.status': 'ongoing',
        },
