import mongoose, { Types } from 'mongoose';
import { IStudent, StudentModel } from '../database/models/student.model';
import { UserModel } from '../database/models/user.model';
import { PaginatedResult, PaginationOptions } from '@/domain/types/pagination.types';
import { CourseStudentModel } from '../database/models/course_student.model';
import { CityModel } from '../database/models/city.model';
import { LicenseCategoryModel } from '../database/models/license_category.model';
import logger from '@/infrastructure/logging/logger';
import { addOwnershipFilter, canAccessResource } from '../utils/queryFilters';
import { Role } from '@/domain/constants/rbac';

export class StudentRepository {
  async getAssignedStudentIds(teacherId: string): Promise<Types.ObjectId[]> {
    if (!mongoose.Types.ObjectId.isValid(teacherId)) return [];

    const teacherObjectId = new mongoose.Types.ObjectId(teacherId);
    const fromEnrollments = await CourseStudentModel.find({ teacher_id: teacherObjectId, status: { $ne: 'canceled' } }).distinct('student_id').exec();
    const fromDirectOwnership = await StudentModel.find({ teacher_id: teacherObjectId }).distinct('_id').exec();

    // Combine both sets of IDs
    const allIds = Array.from(new Set([
      ...fromDirectOwnership.map(id => id.toString()),
      ...fromEnrollments.map(id => id.toString())
    ]));

    logger.info(`Found ${allIds.length} assigned students for teacher ${teacherId}`, { 
      teacherId, 
      fromDirect: fromDirectOwnership.length, 
      fromEnrollments: fromEnrollments.length 
    });

    return allIds.map((id) => new mongoose.Types.ObjectId(id));
  }

  async getStats(currentUser?: any): Promise<any> {
    const match: any = {};

    if (currentUser?.role === Role.TEACHER) {
      const teacherId = currentUser.id || currentUser._id;
      const assignedIds = await this.getAssignedStudentIds(teacherId.toString());
      match._id = { $in: assignedIds };
    }

    const [total, active] = await Promise.all([
      StudentModel.countDocuments(match),
      StudentModel.countDocuments({ ...match, status_detail: 'Đang học' }),
    ]);

    return { total, active };
  }

