    if (currentUser?.role === Role.TEACHER) {
      const assignedIds = await this.getAssignedStudentIds(currentUser.id || currentUser._id);
      const isAssigned = assignedIds.some((aid) => aid.toString() === id);
      if (!isAssigned) {
        logger.warn(`[StudentRepository] Teacher ${currentUser.id} tried to access unassigned student ${id}`);
        return null;
