import { ISettingsRepository } from '@/domain/repositories/settings.repository.interface';
import { Settings } from '@/domain/entities/settings.entity';
import { AppError } from '@/domain/exceptions/app-error';

export class SettingsService {
  constructor(private settingsRepository: ISettingsRepository) {}

  async getSettings(userId: string): Promise<Settings | null> {
    return await this.settingsRepository.findByUserId(userId);
  }

  async updateSettings(userId: string, data: Partial<Omit<Settings, 'id'>>): Promise<Settings | null> {
    // Validate clinic_list if it's being updated
    if (data.clinic_list && Array.isArray(data.clinic_list)) {
      for (const clinic of data.clinic_list) {
        if (!clinic.name?.trim() || !clinic.address?.trim()) {
          throw new AppError('Tên và địa chỉ phòng khám là bắt buộc', 400);
        }
      }
    }
    return await this.settingsRepository.update(userId, data);
  }
}
---

