import { apiClient } from './api';

export interface SystemSettings {
  id?: string;
  regions: string[];
  license_categories?: any[];
  fee_stages?: string[];
  clinic_list?: any[];
  requiredFields?: string[];
  examVenues: string[];
  practiceTargetMinutes: number;
  center_name: string;
  center_website: string;
  center_address: string;
  center_phone: string;
  center_email: string;
  center_fax?: string;
}

export interface LicenseCategory {
  _id?: string;
  id: string;
  type: string;
  name: string;
  fee: string;
  tags: string[];
  inactive: string[];
  dat?: string | null;
}

export interface Clinic {
  name: string;
  info?: string;
  address?: string;
  phone?: string;
  price?: string;
}

export const getSystemSettings = async () => {
  return apiClient('/settings');
};

export const updateSystemSettings = async (data: Partial<SystemSettings>) => {
  return apiClient('/settings', {
    method: 'PATCH',
    body: JSON.stringify(data),
  });
};

