import { Request, Response } from 'express';
import { SettingsService } from '@/application/services/settings.service';
import { SettingsRepository } from '@/infrastructure/database/repositories/settings.repository';
import { catchAsync } from '@/interface/middlewares/catchAsync.middleware';

const settingsRepository = new SettingsRepository();
const settingsService = new SettingsService(settingsRepository);

export const getSettings = catchAsync(async (req: Request, res: Response) => {
  const userId = (req as any).user.id;
  const settings = await settingsService.getSettings(userId);
  res.statusSuccess(settings, 'Settings retrieved successfully');
});

export const updateSettings = catchAsync(async (req: Request, res: Response) => {
  const userId = (req as any).user.id;
  const settings = await settingsService.updateSettings(userId, req.body);
  res.statusSuccess(settings, 'Settings updated successfully');
});

