import { ISettingsRepository } from '@/domain/repositories/settings.repository.interface';
import { Settings } from '@/domain/entities/settings.entity';
import SettingsModel from '@/infrastructure/database/models/settings.model';

export class SettingsRepository implements ISettingsRepository {
  async findByUserId(userId: string): Promise<Settings | null> {
    const settings = await SettingsModel.findOne({ userId });
    if (!settings) return null;
    const obj = settings.toObject({ getters: true, virtuals: true, versionKey: false });
    return {
      ...obj,
      id: obj._id.toString(),
      createdAt: obj.createdAt,
      updatedAt: obj.updatedAt,
    } as unknown as Settings;
  }

  async update(userId: string, data: Partial<Omit<Settings, 'id'>>): Promise<Settings | null> {
    const settings = await SettingsModel.findOneAndUpdate({ userId }, data, { new: true, upsert: true });
    const obj = settings.toObject({ getters: true, virtuals: true, versionKey: false });
    return {
      ...obj,
      id: obj._id.toString(),
      createdAt: obj.createdAt,
      updatedAt: obj.updatedAt,
    } as unknown as Settings;
  }

  async create(data: Omit<Settings, 'id' | 'createdAt' | 'updatedAt'>): Promise<Settings> {
    const settings = await SettingsModel.create(data);
    const obj = settings.toObject({ getters: true, virtuals: true, versionKey: false });
    return {
      ...obj,
      id: obj._id.toString(),
      createdAt: obj.createdAt,
      updatedAt: obj.updatedAt,
    } as unknown as Settings;
  }
}

