import type {} from '../types/express.d';
import { Request, Response, NextFunction } from 'express';
import logger from '@/infrastructure/logging/logger';

export const globalErrorHandler = (err: any, req: Request, res: Response, next: NextFunction) => {
  logger.error(err.message, { stack: err.stack });

  // Handle MongoDB Duplicate Key Error (E11000)
  if (err.code === 11000) {
    const field = Object.keys(err.keyPattern || {})[0] || 'trường';
    let message = `Dữ liệu ${field} đã tồn tại trong hệ thống.`;

    if (field === 'username') message = 'Tên đăng nhập đã tồn tại.';
    if (field === 'email') message = 'Email đã được đăng ký.';
    if (field === 'phone') message = 'Số điện thoại đã được đăng ký.';

    return res.statusError(message, 400);
  }

  // Handle Zod Validation Error (if not handled by validate middleware)
  if (err.name === 'ZodError') {
    return res.statusError('Dữ liệu không hợp lệ', 400);
  }

  const statusCode = err.statusCode || 500;
  const message = statusCode === 500 ? 'Lỗi hệ thống, vui lòng thử lại sau.' : err.message;

  res.statusError(message, statusCode);
};
