import type {} from '../types/express.d';
import { Request, Response, NextFunction } from 'express';

export const jsonResponseMiddleware = (req: Request, res: Response, next: NextFunction) => {
  res.statusSuccess = (data: any, message: string = 'Success') => {
    res.status(200).json({
      success: true,
      message,
      data,
    });
  };

  res.statusError = (message: string, statusCode: number = 500, errors: any = null) => {
    res.status(statusCode).json({
      success: false,
      message,
      errors,
    });
  };

  next();
};

