import { Request, Response, NextFunction } from 'express';
import { ZodSchema, ZodError } from 'zod';
import logger from '@/infrastructure/logging/logger';

export const validate = (schema: ZodSchema) => async (req: Request, res: Response, next: NextFunction) => {
  try {
    const parsed: any = await schema.parseAsync({
      body: req.body,
      query: req.query,
      params: req.params,
    });

    // Crucial: Update req objects with parsed/transformed data (includes defaults)
    // req.body is typically writable by body-parser
    req.body = parsed.body || req.body;

    // query and params can be read-only getters in some Express versions
    if (parsed.query) {
      try {
        (req as any).query = parsed.query;
      } catch (e) {
        Object.assign(req.query, parsed.query);
      }
    }

    if (parsed.params) {
      try {
        (req as any).params = parsed.params;
      } catch (e) {
        Object.assign(req.params, parsed.params);
      }
    }

    return next();
  } catch (error) {
    if (error instanceof ZodError) {
      const errorMessages = error.issues.map((issue: any) => ({
        path: issue.path.join('.'),
        message: issue.message,
      }));

      logger.warn(`Validation Error: ${JSON.stringify(errorMessages)}`);

      return res.status(400).json({
        success: false,
        message: 'Validation failed',
        errors: errorMessages,
      });
    }
    return next(error);
  }
};
