export const bulkUpdateCourseStatus = catchAsync(async (req: Request, res: Response) => {
  const log = ctrlLogger('course.bulk_update_status', req);
  const user = (req as any).user;
  const { courseIds, status } = req.body;

  if (!Array.isArray(courseIds) || courseIds.length === 0) {
    throw new Error('Danh sách khóa học không hợp lệ');
  }
  if (!status) {
    throw new Error('Trạng thái mới không được để trống');
  }

  log.start({ courseIds, status, teacherId: user.id });
  const result = await courseService.bulkUpdateCourseStatus(courseIds, status, user.id || user._id);
  log.success(res, result, `Đã cập nhật ${result.updated} khóa học`);
});

