  useEffect(() => {
    setMounted(true);
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      setStep('preview');
      setReason('');
      setReasonError('');
      setPreview(null);
      fetchPreview();
    } else {
      document.body.style.overflow = 'unset';
    }
