import { apiClient } from './api';

// Types
export interface CancelPreview {
  hasPayments: boolean;
  paymentCount?: number;
  hasDatSessions: boolean;
  datCompleted: boolean;
  totalDatKm?: number;
  warnings: string[];
}

export interface EnrollmentHistory {
  active: any | null;
  history: any[];
}

/**
 * Get enrollment history for a student (active + canceled)
 * GET /api/v1/course-students/student/:studentId
 */
export const getEnrollmentHistory = (studentId: string): Promise<{ success: boolean; data: EnrollmentHistory }> => {
  return apiClient(`/course-students/student/${studentId}`);
};

/**
 * Get cancel preview (warnings before confirming cancellation)
 * GET /api/v1/course-students/:id/cancel-preview
 */
export const getCancelPreview = (enrollmentId: string): Promise<{ success: boolean; data: CancelPreview }> => {
  return apiClient(`/course-students/${enrollmentId}/cancel-preview`);
};

/**
 * Cancel an enrollment (soft delete)
 * PATCH /api/v1/course-students/:id/cancel
 */
export const cancelEnrollment = (
  enrollmentId: string,
  reason: string,
): Promise<{ success: boolean; message: string; data: any }> => {
  return apiClient(`/course-students/${enrollmentId}/cancel`, {
    method: 'PATCH',
    body: JSON.stringify({ reason }),
  });
};
