import type {} from '../types/express.d';
import { Request, Response } from 'express';
import { CourseStudentService } from '@/application/services/course-student.service';
import { catchAsync } from '@/interface/middlewares/catchAsync.middleware';
import { ctrlLogger } from '@/infrastructure/logging/controller-logger';

const courseStudentService = new CourseStudentService();

/**
 * GET /api/v1/course-students/:id
 * Get enrollment by ID
 */
export const getEnrollmentById = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('courseStudent.get_by_id', req);
  const idStr = req.params.id;
  log.start({ enrollmentId: idStr });

  const enrollment = await courseStudentService.getEnrollmentById(idStr, true);
  if (!enrollment) {
    return log.fail('not_found', res, 404, 'Enrollment not found');
  }

  log.success(res, enrollment, 'Lấy thông tin enrollment thành công');
});

/**
 * PATCH /api/v1/course-students/:id/cancel
 * Cancel an enrollment (Soft Delete)
 */
export const cancelEnrollment = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('courseStudent.cancel', req);
  const idStr = req.params.id;
  const { reason } = req.body;
  const userId = req.user?.id || req.user?._id;

  log.start({ enrollmentId: idStr, reason, userId });

  const enrollment = await courseStudentService.cancelEnrollment(idStr, reason || '', userId);

  log.success(res, enrollment, 'Đã hủy khóa học thành công');
});

